(window.webpackJsonp=window.webpackJsonp||[]).push([[159],{786:function(n,r){n.exports="\x3c!-- \r\ntitle: Ftp\r\nsort: \r\n--\x3e \r\n\r\n## 开启服务\r\n\r\n> debian10\r\n\r\n```bash\r\napt update\r\n# 安装vsftpd\r\napt install vsftpd\r\nvsftpd -versions\r\n# 启动服务\r\nsystemctl start vsftpd\r\n# 开防火墙\r\nufw allow 20/tcp\r\nufw allow 21/tcp\r\n# 备份配置\r\ncp /etc/vsftpd.conf /etc/vsftpd.conf.orig\r\n# 添加配置\r\nvim /etc/vsftpd.conf\r\n```\r\n\r\n```conf\r\nlisten=NO\r\nlisten_ipv6=YES\r\nanonymous_enable=NO\r\nlocal_enable=YES\r\nwrite_enable=YES\r\nlocal_umask=022\r\ndirmessage_enable=YES\r\nuse_localtime=YES\r\nxferlog_enable=YES\r\nconnect_from_port_20=YES\r\nchroot_local_user=YES\r\nsecure_chroot_dir=/var/run/vsftpd/empty\r\npam_service_name=vsftpd\r\nrsa_cert_file=/etc/ssl/certs/ssl-cert-snakeoil.pem\r\nrsa_private_key_file=/etc/ssl/private/ssl-cert-snakeoil.key\r\nssl_enable=Yes\r\npasv_enable=Yes\r\npasv_min_port=10000\r\npasv_max_port=10100\r\nallow_writeable_chroot=YES\r\nssl_tlsv1=YES\r\nssl_sslv2=NO\r\nssl_sslv3=NO\r\n```\r\n\r\n```bash\r\n# 重载\r\nsystemctl restart vsftpd\r\n# 新建用户\r\nuseradd -m <user_name>\r\npasswd\r\n# 接下来就可以连接了\r\n```\r\n\r\n## 客户端\r\n\r\n\r\n> 推荐使用[Filezilla](https://www.filezilla.cn/)\r\n\r\n## 问题\r\n\r\n>  Can't open that file: Permission denied\r\n\r\n```bash\r\nsudo chown -fR www ./*\r\nsudo chgrp -fR www ./*\r\n```"}}]);